function findIndex(arr, target) {
  let left = 0;
  let right = arr.length - 1;
  let index = -1;
  while (left <= right) {
    let mid = Math.floor((left + right) / 2);
    if (arr[mid] === target) {
      index = mid;
      left = mid + 1;
